UPDATE genres SET name = N'Hành động',            description = N'Phim hành động, đánh nhau, rượt đuổi', storage_state = 'ACTIVE' WHERE name = 'Action';
UPDATE genres SET name = N'Kinh dị',              description = N'Phim kinh dị, ma quỷ, giật gân',      storage_state = 'ACTIVE' WHERE name = 'Horror';
UPDATE genres SET name = N'Hài',                  description = N'Phim hài hước, giải trí',              storage_state = 'ACTIVE' WHERE name = 'Comedy';
UPDATE genres SET name = N'Tình cảm',             description = N'Phim tình yêu, lãng mạn',              storage_state = 'ACTIVE' WHERE name = 'Romance';
UPDATE genres SET name = N'Khoa học viễn tưởng',  description = N'Phim khoa học, tương lai, vũ trụ',      storage_state = 'ACTIVE' WHERE name = 'Sci-Fi';
UPDATE genres SET name = N'Hoạt hình',            description = N'Phim hoạt hình, anime',                 storage_state = 'ACTIVE' WHERE name = 'Animation';
UPDATE genres SET name = N'Phiêu lưu',            description = N'Phim phiêu lưu, khám phá',             storage_state = 'ACTIVE' WHERE name = 'Adventure';
UPDATE genres SET name = N'Tâm lý',               description = N'Phim tâm lý, xã hội, gia đình',        storage_state = 'ACTIVE' WHERE name = 'Drama';
UPDATE genres SET name = N'Tài liệu',             description = N'Phim tài liệu, khoa học, lịch sử',     storage_state = 'ACTIVE' WHERE name = 'Documentary';
UPDATE genres SET name = N'Âm nhạc',              description = N'Phim ca nhạc, nhạc kịch',               storage_state = 'ACTIVE' WHERE name = 'Musical';

