DECLARE @now DATETIME2 = GETDATE();
DECLARE @r1 BIGINT = (SELECT id FROM rooms WHERE name = N'Phòng 01');
DECLARE @r2 BIGINT = (SELECT id FROM rooms WHERE name = N'Phòng 02');
DECLARE @r3 BIGINT = (SELECT id FROM rooms WHERE name = N'Phòng 03');
DECLARE @r4 BIGINT = (SELECT id FROM rooms WHERE name = N'Phòng IMAX');
DECLARE @r5 BIGINT = (SELECT id FROM rooms WHERE name = N'Phòng VIP');

-- Helper: row labels A=1, B=2, ..., L=12
DECLARE @row INT, @col INT;
DECLARE @rowLabel NVARCHAR(5), @seatNum NVARCHAR(10);
DECLARE @seatType NVARCHAR(20), @seatStatus NVARCHAR(20);

-- ===== Phòng 01: 8 hàng (A-H) x 10 cột, D+E = VIP, H = COUPLE, B5 = BROKEN =====
SET @row = 1;
WHILE @row <= 8
BEGIN
    SET @rowLabel = CHAR(64 + @row); -- A, B, C, ...
    SET @col = 1;
    WHILE @col <= 10
    BEGIN
        SET @seatNum = @rowLabel + CAST(@col AS NVARCHAR);
        SET @seatStatus = N'AVAILABLE';

        -- Hàng H (row=8) = COUPLE
        IF @row = 8
            SET @seatType = N'COUPLE';
        -- Hàng D, E (row=4,5) = VIP
        ELSE IF @row IN (4, 5)
            SET @seatType = N'VIP';
        ELSE
            SET @seatType = N'STANDARD';

        -- B5 = BROKEN
        IF @rowLabel = 'B' AND @col = 5
            SET @seatStatus = N'BROKEN';

        INSERT INTO seats (room_id, row_label, col_number, seat_number, seat_type, status, version, storage_state, created_by, created_at, updated_at)
        VALUES (@r1, @rowLabel, @col, @seatNum, @seatType, @seatStatus, 0, N'ACTIVE', N'system', @now, @now);

        SET @col = @col + 1;
    END
    SET @row = @row + 1;
END

-- ===== Phòng 02: 10 hàng (A-J) x 10 cột, D+E = VIP, J = COUPLE, E7 = BROKEN =====
SET @row = 1;
WHILE @row <= 10
BEGIN
    SET @rowLabel = CHAR(64 + @row);
    SET @col = 1;
    WHILE @col <= 10
    BEGIN
        SET @seatNum = @rowLabel + CAST(@col AS NVARCHAR);
        SET @seatStatus = N'AVAILABLE';

        IF @row = 10
            SET @seatType = N'COUPLE';
        ELSE IF @row IN (4, 5)
            SET @seatType = N'VIP';
        ELSE
            SET @seatType = N'STANDARD';

        IF @rowLabel = 'E' AND @col = 7
            SET @seatStatus = N'BROKEN';

        INSERT INTO seats (room_id, row_label, col_number, seat_number, seat_type, status, version, storage_state, created_by, created_at, updated_at)
        VALUES (@r2, @rowLabel, @col, @seatNum, @seatType, @seatStatus, 0, N'ACTIVE', N'system', @now, @now);

        SET @col = @col + 1;
    END
    SET @row = @row + 1;
END

-- ===== Phòng 03: 6 hàng (A-F) x 10 cột, C+D = VIP, F = COUPLE =====
SET @row = 1;
WHILE @row <= 6
BEGIN
    SET @rowLabel = CHAR(64 + @row);
    SET @col = 1;
    WHILE @col <= 10
    BEGIN
        SET @seatNum = @rowLabel + CAST(@col AS NVARCHAR);
        SET @seatStatus = N'AVAILABLE';

        IF @row = 6
            SET @seatType = N'COUPLE';
        ELSE IF @row IN (3, 4)
            SET @seatType = N'VIP';
        ELSE
            SET @seatType = N'STANDARD';

        INSERT INTO seats (room_id, row_label, col_number, seat_number, seat_type, status, version, storage_state, created_by, created_at, updated_at)
        VALUES (@r3, @rowLabel, @col, @seatNum, @seatType, @seatStatus, 0, N'ACTIVE', N'system', @now, @now);

        SET @col = @col + 1;
    END
    SET @row = @row + 1;
END

-- ===== Phòng IMAX: 10 hàng (A-J) x 12 cột, D+E+F = VIP, J = COUPLE =====
SET @row = 1;
WHILE @row <= 10
BEGIN
    SET @rowLabel = CHAR(64 + @row);
    SET @col = 1;
    WHILE @col <= 12
    BEGIN
        SET @seatNum = @rowLabel + CAST(@col AS NVARCHAR);
        SET @seatStatus = N'AVAILABLE';

        IF @row = 10
            SET @seatType = N'COUPLE';
        ELSE IF @row IN (4, 5, 6)
            SET @seatType = N'VIP';
        ELSE
            SET @seatType = N'STANDARD';

        INSERT INTO seats (room_id, row_label, col_number, seat_number, seat_type, status, version, storage_state, created_by, created_at, updated_at)
        VALUES (@r4, @rowLabel, @col, @seatNum, @seatType, @seatStatus, 0, N'ACTIVE', N'system', @now, @now);

        SET @col = @col + 1;
    END
    SET @row = @row + 1;
END

-- ===== Phòng VIP: 5 hàng (A-E) x 8 cột, B+C = VIP, E = COUPLE =====
SET @row = 1;
WHILE @row <= 5
BEGIN
    SET @rowLabel = CHAR(64 + @row);
    SET @col = 1;
    WHILE @col <= 8
    BEGIN
        SET @seatNum = @rowLabel + CAST(@col AS NVARCHAR);
        SET @seatStatus = N'AVAILABLE';

        IF @row = 5
            SET @seatType = N'COUPLE';
        ELSE IF @row IN (2, 3)
            SET @seatType = N'VIP';
        ELSE
            SET @seatType = N'STANDARD';

        INSERT INTO seats (room_id, row_label, col_number, seat_number, seat_type, status, version, storage_state, created_by, created_at, updated_at)
        VALUES (@r5, @rowLabel, @col, @seatNum, @seatType, @seatStatus, 0, N'ACTIVE', N'system', @now, @now);

        SET @col = @col + 1;
    END
    SET @row = @row + 1;
END

DECLARE @now DATETIME2 = GETDATE(); -- Ngày cơ sở: hôm nay (28/05), ngày mai (29/05), ngày kia (30/05) DECLARE @d0 DATE = CAST(@now AS DATE); -- 28/05 DECLARE @d1 DATE = DATEADD(day, 1, @d0); -- 29/05 DECLARE @d2 DATE = DATEADD(day, 2, @d0); -- 30/05
-- Movie IDs DECLARE @m1 BIGINT = (SELECT id FROM movies WHERE title = N'Thunderbolts*'); DECLARE @m2 BIGINT = (SELECT id FROM movies WHERE title = N'Lật Mặt 8'); DECLARE @m3 BIGINT = (SELECT id FROM movies WHERE title = N'Mission: Impossible - The Final Reckoning'); DECLARE @m4 BIGINT = (SELECT id FROM movies WHERE title = N'Karate Kid: Legends'); DECLARE @m5 BIGINT = (SELECT id FROM movies WHERE title = N'Frozen 3'); DECLARE @m6 BIGINT = (SELECT id FROM movies WHERE title = N'How to Train Your Dragon'); DECLARE @m7 BIGINT = (SELECT id FROM movies WHERE title = N'Jurassic World: Rebirth'); DECLARE @m8 BIGINT = (SELECT id FROM movies WHERE title = N'Cô Dâu Hào Môn'); DECLARE @m9 BIGINT = (SELECT id FROM movies WHERE title = N'Địa Đạo: Mặt Trời Trong Bóng Tối'); DECLARE @m10 BIGINT = (SELECT id FROM movies WHERE title = N'The Bride');
-- Room IDs DECLARE @r1 BIGINT = (SELECT id FROM rooms WHERE name = N'Phòng 01'); DECLARE @r2 BIGINT = (SELECT id FROM rooms WHERE name = N'Phòng 02'); DECLARE @r3 BIGINT = (SELECT id FROM rooms WHERE name = N'Phòng 03'); DECLARE @r4 BIGINT = (SELECT id FROM rooms WHERE name = N'Phòng IMAX'); DECLARE @r5 BIGINT = (SELECT id FROM rooms WHERE name = N'Phòng VIP');
